import React from 'react';

const KPIStrip = ({ kpis }) => {
  const kpiConfig = [
    {
      label: 'Total Pipeline',
      value: `$${kpis.totalPipeline}B`,
      sub: `${(kpis.pendingApprovals || 0) + (kpis.approvedYTD || 0)} total submissions`,
      color: 'teal'
    },
    {
      label: 'Pending Approvals',
      value: kpis.pendingApprovals ?? '‚Äî',
      sub: 'Active & under review',
      color: 'amber'
    },
    {
      label: 'Approved (12mo)',
      value: kpis.approvedYTD ?? '‚Äî',
      sub: 'Last 12 months',
      color: 'green'
    },
    {
      label: 'Avg Cycle Time',
      value: kpis.avgCycleTime != null && kpis.avgCycleTime > 0 ? `${kpis.avgCycleTime}d` : '‚Äî',
      sub: 'Submission to approval',
      color: 'blue'
    },
    {
      label: 'CRLs Received',
      value: kpis.crlCount ?? '‚Äî',
      sub: kpis.crlCount > 0 ? 'Requires response' : 'No active CRLs',
      color: 'red'
    }
  ];

  return (
    <div className="kpi-strip">
      {kpiConfig.map((kpi, index) => (
        <div key={index} className={`kpi ${kpi.color}`}>
          <div className="kpi-label">{kpi.label}</div>
          <div className="kpi-value">{kpi.value}</div>
          <div className="kpi-sub">{kpi.sub}</div>
        </div>
      ))}
    </div>
  );
};

export default KPIStrip;
